                average_volume = sum(volumes) / len(volumes)
                all_results.append({
                    'Symbol': symbol,
                    'Company Description': company_descriptions.get(symbol, 'N/A'),
                    'Average Daily Trading Volume 2008': average_volume
                })
    except Exception as e:
        # In case of any error during the query or processing, print the error and continue.
        # This prevents a single bad symbol from stopping the entire process.
        print(f'Error processing symbol {symbol}: {e}')

print('__RESULT__:')
print(json.dumps(all_results))
